import android.content.Context
import android.content.SharedPreferences
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch

class MainActivity : AppCompatActivity() {

    private lateinit var sharedPreferences: SharedPreferences
    private val prefsFileName = "auth_prefs"
    private val authenticatedKey = "is_authenticated"

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        sharedPreferences = getSharedPreferences(prefsFileName, Context.MODE_PRIVATE)

        if (isAuthenticated()) {
            bypassLogin()
        } else {
            showBiometricPrompt()
        }
    }

    private fun isAuthenticated(): Boolean {
        return sharedPreferences.getBoolean(authenticatedKey, false)
    }

    private fun bypassLogin() {
        // Navigate to main application screen
    }

    private fun showBiometricPrompt() {
        val executor = ContextCompat.getMainExecutor(this)
        val biometricPrompt = BiometricPrompt(this, executor, object : BiometricPrompt.AuthenticationCallback() {

            override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                super.onAuthenticationSucceeded(result)
                storeAuthenticationFlag()
                bypassLogin()
            }

            override fun onAuthenticationFailed() {
                super.onAuthenticationFailed()
                // Show fallback password option
                showPasswordLogin()
            }
        })

        val promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Biometric login")
            .setSubtitle("Log in using your biometric credential")
            .setDescription("Place your finger on the sensor")
            .setNegativeButtonText("Use password")
            .build()

        biometricPrompt.authenticate(promptInfo)
    }

    private fun storeAuthenticationFlag() {
        CoroutineScope(Dispatchers.IO).launch {
            sharedPreferences.edit().putBoolean(authenticatedKey, true).apply()
        }
    }

    private fun showPasswordLogin() {
        // Show the password input field for fallback
    }
}